package com.abc.studentportal.postgres.entity;
import com.abc.studentportal.student.domain.StudentStatus; import jakarta.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="students") public class StudentEntity {
 @Id private UUID id; @Column(name="student_number",nullable=false,unique=true) private String studentNumber; @Column(nullable=false,unique=true) private String email; @Column(name="first_name",nullable=false) private String firstName; @Column(name="last_name",nullable=false) private String lastName; @Enumerated(EnumType.STRING) @Column(nullable=false) private StudentStatus status; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="department_id",nullable=false) private DepartmentEntity department; @Column(name="created_at",nullable=false) private Instant createdAt; @Column(name="updated_at",nullable=false) private Instant updatedAt; @Version private long version; @OneToOne(mappedBy="student",fetch=FetchType.LAZY,orphanRemoval=true) private StudentProfileEntity profile;
 protected StudentEntity(){} public StudentEntity(UUID id,String sn,String fn,String ln,String email,StudentStatus st,UUID departmentId,Instant c,Instant u){this.id=id;this.studentNumber=sn;this.firstName=fn;this.lastName=ln;this.email=email;this.status=st;this.department=new DepartmentEntity(departmentId,null,null,null,c,u);this.createdAt=c;this.updatedAt=u;} public UUID getId(){return id;} public String getStudentNumber(){return studentNumber;} public String getFirstName(){return firstName;} public String getLastName(){return lastName;} public String getEmail(){return email;} public StudentStatus getStatus(){return status;} public DepartmentEntity getDepartment(){return department;} public Instant getCreatedAt(){return createdAt;} public Instant getUpdatedAt(){return updatedAt;} public long getVersion(){return version;}
}
